if (hp < 50) {
  console.log("⚠️ HP baixo! Cuidado!");
}

console.log("Jogo continua...");

let nota: number = 7;

if (nota >= 6) {
  console.log("Aprovado! 🎉");
} else {
  console.log("Reprovado 😢");
}

let temperatura: number = 35;

if (temperatura >= 35) {
  console.log("🔥 Muito quente!");
} else if (temperatura >= 25) {
  console.log("☀️ Agradável");
} else if (temperatura >= 15) {
  console.log("🧥 Um pouco frio");
} else {
  console.log("🥶 Congelando!");
}

let hp: number = 100;
let temEscudo: boolean = true;

// E (&&): ambas precisam ser true
if (hp > 50 && temEscudo) {
  console.log("Pode atacar com segurança!");
}

// OU (||): basta uma ser true
let temPocao: boolean = false;
if (temEscudo || temPocao) {
  console.log("Tem pelo menos um item de proteção");
}

// NÃO (!): inverte
if (!temPocao) {
  console.log("Sem poção! Compre uma.");
}

